1	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteStep = { op: "quote"; items: Item[] };
4	type Damage = { itemType: string; amount: number };
5	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer: Customer; steps: Step[] };
8	type QuoteResult = { premium: number };
9	type ClaimResult = { payout: number; remainingCap: number };
10	type StepResult = QuoteResult | ClaimResult;
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE = 0.1;
14	const CURSE_SURCHARGE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT = 0.2;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
20	
21	const BASE_PREMIUM: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const INSURANCE_VALUE: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const DEDUCTIBLE = 100;
40	const CAP_MULTIPLIER = 2;
41	const REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD = 8;
42	const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	const BLOCK_SIZE = 3;
46	const BLOCK_PREMIUM = 60;
47	
48	const isBlock = (type: string, count: number): boolean =>
49	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
50	
51	const groupPremium = (type: string, count: number): number =>
52	  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;
53	
54	const countByType = (items: Item[]): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
57	  return counts;
58	};
59	
60	const sumBasePremiumsByGroup = (items: Item[]): number =>
61	  [...countByType(items)].reduce(
62	    (total, [type, count]) => total + groupPremium(type, count),
63	    0,
64	  );
65	
66	const isCursed = (item: Item): boolean => item.cursed === true;
67	const isHighlyEnchanted = (item: Item): boolean =>
68	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
69	const isLoyalCustomer = (customer: Customer): boolean =>
70	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
71	
72	const surchargeRateFor = (item: Item): number =>
73	  (isCursed(item) ? CURSE_SURCHARGE : 0)
74	  + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
75	
76	const perItemSurcharges = (items: Item[]): number =>
77	  items.reduce(
78	    (total, item) => total + BASE_PREMIUM[item.type] * surchargeRateFor(item),
79	    0,
80	  );
81	
82	const policyWideAdjustments = (
83	  policyBase: number,
84	  customer: Customer,
85	  isFollowUp: boolean,
86	): number => {
87	  const loyaltyDiscount = isLoyalCustomer(customer) ? LOYALTY_DISCOUNT : 0;
88	  const followUpDiscount = isFollowUp ? FOLLOWUP_CONTRACT_DISCOUNT : 0;
89	  return policyBase * (FIRST_INSURANCE_SURCHARGE - loyaltyDiscount - followUpDiscount);
90	};
91	
92	const quotePremiumFor = (
93	  customer: Customer,
94	  { items }: QuoteStep,
95	  isFollowUp: boolean,
96	): QuoteResult => {
97	  const policyBase = sumBasePremiumsByGroup(items);
98	  const total =
99	    policyBase
100	    + perItemSurcharges(items)
101	    + policyWideAdjustments(policyBase, customer, isFollowUp)
102	    + PROCESSING_FEE;
103	  return { premium: Math.ceil(total) };
104	};
105	
106	type Policy = { items: Item[]; remainingCap: number };
107	
108	const insuranceSumFor = (items: Item[]): number =>
109	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
110	
111	const createPolicy = ({ items }: QuoteStep): Policy => ({
112	  items,
113	  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
114	});
115	
116	const reimbursementRateFor = (item: Item): number =>
117	  (item.enchantment ?? 0) >= REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD
118	    ? HIGH_ENCHANTMENT_REIMBURSEMENT
119	    : 1;
120	
121	const findItem = (policy: Policy, itemType: string): Item => {
122	  const item = policy.items.find((i) => i.type === itemType);
123	  if (item === undefined) throw new Error(`Item not in policy: ${itemType}`);
124	  return item;
125	};
126	
127	const payoutForDamage = (policy: Policy, damage: Damage): number => {
128	  const item = findItem(policy, damage.itemType);
129	  const reimbursed = damage.amount * reimbursementRateFor(item);
130	  return Math.max(0, reimbursed - DEDUCTIBLE);
131	};
132	
133	const totalPayout = (policy: Policy, damages: Damage[]): number =>
134	  damages.reduce((sum, d) => sum + payoutForDamage(policy, d), 0);
135	
136	const capAndRoundDown = (amount: number, cap: number): number =>
137	  Math.floor(Math.min(amount, cap));
138	
139	const settleClaim = (policy: Policy, { incident }: ClaimStep): ClaimResult => {
140	  const uncapped = totalPayout(policy, incident.damages);
141	  const payout = capAndRoundDown(uncapped, policy.remainingCap);
142	  policy.remainingCap -= payout;
143	  return { payout, remainingCap: policy.remainingCap };
144	};
145	
146	export const runScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
147	  const policies: Policy[] = [];
148	  const handle = (step: Step): StepResult => {
149	    if (step.op === "quote") {
150	      const isFollowUp = policies.length > 0;
151	      policies.push(createPolicy(step));
152	      return quotePremiumFor(customer, step, isFollowUp);
153	    }
154	    return settleClaim(policies[step.policy], step);
155	  };
156	  return { results: steps.map(handle) };
157	};
158

