44	  // === Components and blocks (base premium examples) ===
45	  it("2 runes → 50 G base premium (no block) → +10% first +5 fee = 60 G", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 60 }] });

